index 1a1a1a..2b2b2b 100644
--- a/src/users/import.ts
+++ b/src/users/import.ts
@@ -1,10 +1,16 @@
 import { RawUser, User } from './types';

-export function process(raw: RawUser): User {
-  return { ...raw, email: raw.email };
-}
+/**
+ * Normalize and deduplicate-ready email string for a raw user record.
+ */
+export function process(raw: RawUser): User {
+  const email = raw.email.trim().toLowerCase();
+  return { ...raw, email };
+}

diff --git a/src/notifications/send.ts b/src/notifications/send.ts
index 3c3c3c..4d4d4d 100644
--- a/src/notifications/send.ts
+++ b/src/notifications/send.ts
@@ -1,9 +1,13 @@
 import { Message } from './types';

-export function send(msg: Message): Promise<void> {
-  return transport.deliver(msg);
-}
+/**
+ * Send a message. Pass `true` to skip the rate limiter for system notifications.
+ */
+export function send(msg: Message, flag: boolean): Promise<void> {
+  if (flag) return transport.deliverUnthrottled(msg);
+  return transport.deliver(msg);
+}

